import React from "react"
import Collapsible from 'react-collapsible'
import '../collapse.css'

class Evalulation extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            results: [], stage: 0, teamInfo: {}
        };
    }

    goBackFirstScreen = () => {
      this.setState({stage: 0});
      this.setState({teamInfo: {}});
    }

    nameClick = (teamInfo) => {
      this.setState({stage: 1});
      this.setState({teamInfo: teamInfo});

      let headers = new Headers();

      headers.append('Content-Type', 'application/json');
      headers.append('Accept', 'application/json');

      var userIDs = []
      userIDs.push(teamInfo.userID)

      for (let y in teamInfo.members) {
        userIDs.push(teamInfo.members[y].userID)
      }


      var backUrl = `http://localhost:9000/medhubincomplete`
      fetch(backUrl, {
        "method": "POST",
        headers: headers,
        body: JSON.stringify({userIDs: userIDs})

      })
      .then(response => response.json())
      .then(response => {
        console.log(response);
        //this.setState({results: response})
        //_forEach(response, d => console.log(d.name))
        //console.log(this.state.results)
      })
      .catch(err => {
        console.log(err);
      });


    }


        componentDidMount() {


          const search = this.props.location.search;
          const params = new URLSearchParams(search);
          const day = params.get('day');
          const month = params.get('month');


          //console.log(day)
          //console.log(month)

          var query = ""
          if (day != null && month != null) {
            query = "?day=" + day + "&month=" + month
          }

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            //headers.append('Access-Control-Allow-Origin', 'http://localhost:3000');
            //headers.append('Access-Control-Allow-Credentials', 'true');
            //var backUrl = `http://localhost:9000/amioncall`+query
            //var backUrl = `http://192.168.2.83:9000/amioncall`+query
            var backUrl = `http://localhost:9000/amiontest`+query

            fetch(backUrl, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({results: response})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)
              })
              .catch(err => {
                console.log(err);
              });


          }

          render() {


            var todayDate = "Loading ..."
            var content = []


            if (this.state.stage === 1) {
              var teamHtml = ""

              todayDate = "Date: " + this.state.teamInfo.date

              var color = "black"
              if (this.state.teamInfo.turnover) {
                color = "red"
              }


              teamHtml = <div style={{marginBottom: '10px', color: color}} ><b>{this.state.teamInfo.assignment }: <u>{this.state.teamInfo.name} * medHubID: ({this.state.teamInfo.userID})</u></b></div>

              var residentsContent = []
              for (let y in this.state.teamInfo.members) {

                var colorRes = "black"
                if (this.state.teamInfo.members[y].turnover) {
                  colorRes = "red"
                }


                residentsContent.push(<div style={{marginLeft: '10px', color: colorRes}}>- {this.state.teamInfo.members[y].name} * medHubID: ({this.state.teamInfo.members[y].userID})</div>)
              }


              content.push(<button onClick={(e) => this.goBackFirstScreen()} style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow"}}>Go Back</button>)
              content.push(<div>************************************************</div>)

              content.push(teamHtml)
              content.push(<Collapsible trigger="Start here">
              <p>
                This is the collapsible content. It can be any element or React
                component you like.
              </p>
              <p>
                It can even be another Collapsible component. Check out the next
                section!
              </p>
            </Collapsible>)


              content.push(residentsContent)
              content.push(<div>&nbsp;</div>)

            }







            if (this.state.stage === 0) {

            var teamHtml = ""
                for (let x in this.state.results.team) {

                      //console.log(this.state.results[x])
                      todayDate = "Date: " + this.state.results.team[x].date

                      var color = "black"
                      if (this.state.results.team[x].turnover) {
                        color = "red"
                      }


                      teamHtml = <div style={{marginBottom: '10px', color: color}} id={'team' + x} onClick={() => this.nameClick(this.state.results.team[x])}><b>{this.state.results.team[x].assignment }: <u>{this.state.results.team[x].name} * medHubID: ({this.state.results.team[x].userID})</u></b></div>



                      var residentsContent = []
                      for (let y in this.state.results.team[x].members) {

                        /*
                        fetch(`https://applet-test.ucsf.edu/residencyAPIs/findid?name=` + this.state.results[x].residents[y].name, {
                          "method": "GET"
                        })
                        .then(response => response.json())
                        .then(response => {
                          console.log(response);
                          //this.setState({results: response})
                          //_forEach(response, d => console.log(d.name))
                          //console.log(this.state.results)
                          residentsContent.push(<div style={{marginLeft: '10px'}}>- {this.state.results[x].residents[y].assignment}: {this.state.results[x].residents[y].name} - {response}</div>)
                        })
                        .catch(err => {
                          console.log(err);
                        });
                      */




                        var colorRes = "black"
                        if (this.state.results.team[x].members[y].turnover) {
                          colorRes = "red"
                        }


                        residentsContent.push(<div style={{marginLeft: '10px', color: colorRes}}>- {this.state.results.team[x].members[y].name} * medHubID: ({this.state.results.team[x].members[y].userID})</div>)
                      }

                    content.push(<div>************************************************</div>)

                    content.push(teamHtml)
                    content.push(residentsContent)
                    content.push(<div>&nbsp;</div>)

                }


                /*
                for (var x in this.state.results.eval) {

                  var colorWard = "green"
                  if (this.state.results.eval[x].ward) {
                    colorWard = "blue"
                  }

                  content.push(<div style={{marginLeft: '10px', color: colorWard}}> Evalualtor: {this.state.results.eval[x].evaluator} ({this.state.results.eval[x].evaluatorID}) - Program: {this.state.results.eval[x].evaluatorProgramID} - &gt;  Evalulatee: {this.state.results.eval[x].evaluatee} ({this.state.results.eval[x].evaluateeID}) - Program: {this.state.results.eval[x].evaluateeProgramID}</div>)


                }*/

              }






            return (
                <div className="container">
                  <div className="row justify-content-center">
                    <div className="col-md-8">
                      <h1 className="display-4 text-center">{todayDate}</h1>


{content}



                    </div>
                  </div>
                </div>
            );
          }


  };

  export default Evalulation
